package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that windows elements into sessions based on market trading session
 * boundaries (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT) rather than fixed time intervals.
 *
 * <p>This assigner is useful for financial applications where aggregations must align with trading
 * sessions. It handles:
 * <ul>
 *   <li>Regular trading sessions within a single day
 *   <li>Pre/post-market sessions
 *   <li>Overnight sessions (e.g., futures markets)
 * </ul>
 *
 * <p>Windows cannot overlap and are determined by the session boundaries for a given market.
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow assigner with the specified market configuration.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone for the market (e.g., ZoneId.of("America/New_York"))
     * @param sessionOpen The opening time of the session in the market's timezone
     * @param sessionClose The closing time of the session in the market's timezone
     */
    public PricingSessionWindow(String marketId, ZoneId timezone, LocalTime sessionOpen,
            LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("Session open and close times cannot be null");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    /**
     * Factory method to create a PricingSessionWindow for a given market.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone for the market
     * @param open The opening time of the session in the market's timezone
     * @param close The closing time of the session in the market's timezone
     * @return A new PricingSessionWindow assigner
     */
    public static PricingSessionWindow forMarket(String marketId, ZoneId timezone,
            LocalTime open, LocalTime close) {
        return new PricingSessionWindow(marketId, timezone, open, close);
    }

    /**
     * Determines which trading session a timestamp belongs to and returns a TimeWindow for that
     * session.
     *
     * <p>The method converts the timestamp to the market's timezone, extracts the date, and
     * determines the session start and end times based on the market's opening and closing times.
     *
     * <p>For example, if the market opens at 09:30 ET and closes at 16:00 ET:
     * <ul>
     *   <li>A timestamp at 2024-03-15 14:30 ET would be assigned to the session window
     *       [2024-03-15 09:30 ET, 2024-03-15 16:00 ET)
     *   <li>A timestamp at 2024-03-15 08:00 ET (pre-market) would still be assigned to the same
     *       session window if it's on the same trading day
     * </ul>
     *
     * @param element The element being assigned (not used in this implementation)
     * @param timestamp The timestamp of the element in milliseconds since epoch
     * @param context The window assigner context
     * @return A collection containing a single TimeWindow for the trading session
     */
    @Override
    public Collection<TimeWindow> assignWindows(Object element, long timestamp,
            WindowAssignerContext context) {
        // Convert the timestamp to the market's timezone
        ZonedDateTime zonedDateTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);

        // Get the trading day (date in the market's timezone)
        java.time.LocalDate tradingDay = zonedDateTime.toLocalDate();

        // Create the session start and end times
        ZonedDateTime sessionStartZoned = ZonedDateTime.of(tradingDay, sessionOpen, timezone);
        ZonedDateTime sessionEndZoned = ZonedDateTime.of(tradingDay, sessionClose, timezone);

        // Convert back to epoch milliseconds
        long sessionStart = sessionStartZoned.toInstant().toEpochMilli();
        long sessionEnd = sessionEndZoned.toInstant().toEpochMilli();

        return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public String toString() {
        return "PricingSessionWindow(marketId=" + marketId + ", open=" + sessionOpen
                + ", close=" + sessionClose + ")";
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    /**
