     * @return FIRE if the watermark has passed the window end, CONTINUE otherwise
     * @throws Exception If an error occurs during processing
     */
    @Override
    public TriggerResult onElement(Object element, long timestamp, TimeWindow window,
            TriggerContext ctx) throws Exception {
        long windowEnd = window.maxTimestamp();

        if (windowEnd <= ctx.getCurrentWatermark()) {
            // If the watermark is already past the window end, fire immediately
            return TriggerResult.FIRE;
        } else {
            // Register a timer to fire at the window end
            ctx.registerEventTimeTimer(windowEnd);
            return TriggerResult.CONTINUE;
        }
    }

    /**
     * Called when an event-time timer fires.
     *
     * <p>Fires the window if the current time matches the window end.
     *
     * @param time The timestamp at which the timer fired
     * @param window The window for which the timer fired
     * @param ctx A context object that can be used to register timer callbacks
     * @return FIRE if the time matches the window end, CONTINUE otherwise
     */
    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    }

    /**
     * Called when a processing-time timer fires.
     *
     * <p>For session windows based on event time, processing-time timers are not used, so this
     * just returns CONTINUE.
     *
     * @param time The timestamp at which the timer fired
     * @param window The window for which the timer fired
     * @param ctx A context object that can be used to register timer callbacks
     * @return CONTINUE
     */
    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx) {
        return TriggerResult.CONTINUE;
    }

    /**
     * Clears any state and timers for the given window.
     *
     * <p>Deletes the event-time timer that was registered for the window end.
     *
     * @param window The window being cleared
     * @param ctx A context object that can be used to clean up state and timers
     * @throws Exception If an error occurs during cleanup
     */
    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        ctx.deleteEventTimeTimer(window.maxTimestamp());
    }

    /**
     * Returns true to indicate that this trigger supports merging of windows.
     *
     * <p>This is necessary because {@link
     * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow} is a merging
     * window assigner.
     *
     * @return true
     */
    @Override
    public boolean canMerge() {
        return true;
    }

    /**
     * Called when windows are merged.
     *
     * <p>Re-registers the event-time timer for the merged window if the watermark hasn't passed
     * the window end yet.
     *
     * @param window The new window resulting from the merge
     * @param ctx A context object that can be used to register timer callbacks and access state
     * @throws Exception If an error occurs during merging
     */
    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
        // Only register a timer if the watermark has not yet passed the end of the merged window.
        // This is in line with the logic in onElement(). If the watermark is past the end of
        // the window onElement() will fire and setting a timer here would fire the window twice.
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a pricing session trigger that fires at the end of the trading session (market
     * close).
     *
     * <p>Once the trigger fires all elements are discarded. Elements that arrive late
     * immediately trigger window evaluation with just that one element.
     *
     * @return A new PricingSessionTrigger instance
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}

